contracts/EnergyToken.sol.content:
// SPDX-License-Identifier: UNLICENSED

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract EnergyToken is ERC20, Ownable {
    constructor(address _initialOwner) 
    ERC20("Energy Token", "ETK") 
    Ownable(_initialOwner)
    {}

    function mint(address to, uint256 amt) public onlyOwner{
        _mint(to, amt);
    }

    function burn(address from, uint256 amt) public onlyOwner{
        _burn(from, amt);
    }
    
}

contracts/interfaces/IEnergyToken.sol.content:
// SPDX-License-Identifier: UNLICENSED

pragma solidity ^0.8.0;

interface IEnergyToken {
    function transfer(
        address recipient, uint256 amount
    ) external returns (bool);

    function transferFrom(
        address sender, address recipient, uint256 amount
    ) external returns (bool);

    function balanceOf(
        address account
    ) external view returns (uint256);
    
    function approve(
        address spender, uint256 amount
    ) external returns (bool);

    function allowance(
        address owner, address spender
    ) external view returns (uint256);
}

contracts/interfaces/IMicrogridRegistry..content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.0;

interface IMicrogridRegistry {
    function getOwner(
        uint256 _id
        ) external view returns (address);
    
    function isMicrogridActive(
        uint256 _id
        ) external view returns (bool);
    
    function getAvailableEnergy(
        uint256 _id
        ) external view returns(uint256);

    function increaseReservedEnergy(
        uint256 _id, 
        uint256 _amount
        ) external;

    function decreaseReservedEnergy(
        uint256 _id,
        uint256 _amount
        ) external;

    function getPricingData(
        uint256 id
    ) external view returns (
        uint256 generation,
        uint256 demand,
        uint256 batteryLevel,
        uint256 maxCapacity,
        uint256 reservedEnergy
    );
}

