// SPDX-License-Identifier: UNLICENSED

pragma solidity ^0.8.0;

import './interfaces/IEnergyToken.sol';
import './interfaces/IMicrogridRegistry.sol';
import './PricingLibrary.sol';

contract Marketplace {
    IEnergyToken public energyToken;
    IMicrogridRegistry public registry;

    constructor(address _energyTokenAddress, address _registryAddress) {
        energyToken = IEnergyToken(_energyTokenAddress);
        registry = IMicrogridRegistry(_registryAddress);
    }

    enum OfferStatus {
        ACTIVE,
        PARTIALLY_FILLED,
        FILLED,
        CANCELLED,
        EXPIRED
    }

    struct Offer {
        uint256 offerId;
        uint256 microgridId;

        uint256 totalEnergy; // in kWh
        uint256 remainingEnergy; // in kWh
        uint256 soldEnergy; // in kWh

        uint256 suggestedPrice; // in ETK per kWh (from adaptive pricing)
        uint256 sellingPrice; // in ETK per kWh (set by seller)
        address seller;

        uint256 createdAt; // timestamp
        uint256 updatedAt; // timestamp
        uint256 expiresAt; // timestamp
        OfferStatus status;
    }

    uint256 constant OFFER_EXPIRATION_TIME = 1 days;
    uint256 public nextOfferId;
    mapping(uint256 => Offer) public offers;
    mapping(uint256 => uint256[]) public microgridOffers; // microgridId => offerIds
    mapping(address => uint256[]) public sellerOffers; // seller => offerIds
    mapping(uint256 => uint256) public activeOfferCount; // active offer count per microgrid

    // events
    event OfferCreated(uint256 indexed offerId, uint256 indexed microgridId, uint256 totalEnergy, uint256 suggestedPrice, uint256 sellingPrice, address indexed seller);
    event EnergyPurchased(uint256 indexed offerId, uint256 energyBought, address indexed buyer, uint256 totalCost);
    event OfferCancelled(uint256 indexed offerId, address indexed seller);
    event OfferStatusUpdated(uint256 indexed offerId, OfferStatus newStatus);

    // modifiers
    modifier offerExists(uint256 _offerId) {
        require(_offerId < nextOfferId, "Offer does not exist");
        _;
    }

    modifier onlySeller(uint256 _offerId){
        require(offers[_offerId].seller == msg.sender, "Not the seller of this offer");
        _;
    }

    // functions
    function createOffer(uint256 _microgridId, uint256 _energyAmount, uint256 _pricePerUnit) external {
        require(_energyAmount > 0, "Energy amount must be greater than 0");
        require(_pricePerUnit > 0, "Price per unit must be greater than 0");
        require(registry.getOwner(_microgridId) == msg.sender, "Not the owner of this microgrid");
        require(registry.isMicrogridActive(_microgridId), "Microgrid is not active");
        require(registry.getAvailableEnergy(_microgridId) >= _energyAmount, "Not enough available energy in the microgrid");

        uint256 offerId = nextOfferId++;

        (
            uint256 energyGeneration, 
            uint256 energyDemand, 
            uint256 batteryLevel, 
            uint256 maxCapacity, 
            uint256 reservedEnergy
        ) = registry.getPricingData(_microgridId);

        uint256 suggestedPrice = PricingLibrary.calculatePrice(energyGeneration,energyDemand, batteryLevel, maxCapacity, reservedEnergy);

        uint256 minPrice = (suggestedPrice * 80) / 100;
        uint256 maxPrice = (suggestedPrice * 120) / 100;

        require((_pricePerUnit >= minPrice && _pricePerUnit <= maxPrice), "Price is out of market range");

        registry.increaseReservedEnergy(_microgridId, _energyAmount);
        
        offers[offerId] = Offer({
            offerId: offerId,
            microgridId: _microgridId,
            seller: msg.sender,
            totalEnergy: _energyAmount,
            remainingEnergy: _energyAmount,
            soldEnergy: 0,
            suggestedPrice: suggestedPrice,
            sellingPrice: _pricePerUnit,
            createdAt: block.timestamp,
            updatedAt: block.timestamp,
            expiresAt: block.timestamp + OFFER_EXPIRATION_TIME, // offer expires in 1 day
            status: OfferStatus.ACTIVE
        });

        microgridOffers[_microgridId].push(offerId);
        sellerOffers[msg.sender].push(offerId);
        activeOfferCount[_microgridId]++;

        emit OfferCreated(offerId, _microgridId, _energyAmount, suggestedPrice, _pricePerUnit, msg.sender);
    }

    function isOfferOpen(uint256 _offerId) public view returns (bool) {
        return offers[_offerId].status == OfferStatus.ACTIVE || offers[_offerId].status == OfferStatus.PARTIALLY_FILLED;
    }

    function buyEnergy(uint256 _offerId, uint256 _amt) external offerExists(_offerId) {
        require(isOfferOpen(_offerId), "Offer isn't open");
        if (block.timestamp >= offers[_offerId].expiresAt) {
            _closeOffer(_offerId, OfferStatus.EXPIRED);
            revert("Offer has expired");
        }
        require(msg.sender != offers[_offerId].seller, "Seller cannot buy their own energy");
        require(_amt > 0, "Amount must be greater than 0");
        require(offers[_offerId].remainingEnergy >= _amt, "Not enough energy available in the offer");

        uint256 totalCost = PricingLibrary.calculateCost(offers[_offerId].sellingPrice, _amt);

        // Check buyer balance
        require(energyToken.balanceOf(msg.sender) >= totalCost, "Insufficient ETK balance");

        // Check Marketplace allowance
        require(energyToken.allowance(msg.sender, address(this)) >= totalCost, "Approve Marketplace to spend your ETK first");

        // Transfer tokens
        require(energyToken.transferFrom(msg.sender, offers[_offerId].seller, totalCost),"Transfer failed");

        // update offer
        offers[_offerId].remainingEnergy -= _amt;
        offers[_offerId].soldEnergy += _amt;

        // release reserved energy
        registry.decreaseReservedEnergy(offers[_offerId].microgridId, _amt);

        // updated time
        offers[_offerId].updatedAt = block.timestamp;

        // update status
        if(offers[_offerId].remainingEnergy == 0){
            activeOfferCount[offers[_offerId].microgridId]--;
            offers[_offerId].status = OfferStatus.FILLED;
        } else {
            offers[_offerId].status = OfferStatus.PARTIALLY_FILLED;
        }

        emit OfferStatusUpdated(_offerId, offers[_offerId].status);
        emit EnergyPurchased(_offerId, _amt, msg.sender, totalCost);
    }

    function cancelOffer(uint256 _offerId) external offerExists(_offerId) onlySeller(_offerId){
        _closeOffer(_offerId, OfferStatus.CANCELLED);
        
        emit OfferCancelled(_offerId,msg.sender);
    }

    function expireOffer(uint256 _offerId) public offerExists(_offerId) {
        require(offers[_offerId].expiresAt <= block.timestamp, "Offer has not expired yet");
        _closeOffer(_offerId, OfferStatus.EXPIRED);
    }

    function _closeOffer(uint256 _offerId, OfferStatus status) internal{
        require(isOfferOpen(_offerId),"Offer already closed");
        if (offers[_offerId].remainingEnergy > 0) {
            registry.decreaseReservedEnergy(
                offers[_offerId].microgridId,
                offers[_offerId].remainingEnergy
            );
        }

        offers[_offerId].remainingEnergy = 0;
        offers[_offerId].status = status;
        offers[_offerId].updatedAt = block.timestamp;

        activeOfferCount[offers[_offerId].microgridId]--;

        emit OfferStatusUpdated(_offerId,status);
    }
}

contracts/MicrogridRegistry.sol.content:
// SPDX-License-Identifier: UNLICENSED

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";

contract MicrogridRegistry is Ownable {

    constructor(address _owner) Ownable(_owner) {}

    struct Microgrid {
        uint256 id;
        string name;
        address owner;
        uint256 latitude; // in microdegrees
        uint256 longitude; // in microdegrees

        uint256 energyGenerated; // in kWh
        uint256 energyDemand; // in kWh
        uint256 batteryLevel;
        uint256 maxCapacity; // in kWh
        uint256 reservedEnergy; // in kWh

        bool isActive;
        uint256 lastUpdated; // timestamp
    }

    uint256 public nextId;
    mapping(uint256 => Microgrid) public microgrids;
    mapping(address => bool) public isRegistered;

    address public marketplaceAddress;

    // events
    event MicrogridRegistered(uint256 indexed id, address indexed owner, string name, uint256 latitude, uint256 longitude);
    event StatusUpdated(uint256 indexed id, uint256 energyGenerated, uint256 energyDemand, uint256 batteryLevel, uint256 lastUpdated);
    event ReservedEnergyUpdated(uint256 indexed id, uint256 reservedEnergy);

    //modifiers
    modifier onlyMicrogridOwner(uint256 id) {
        require(microgrids[id].owner == msg.sender, "Not the owner of this microgrid");
        _;
    }

    modifier onlyMarketplace() {
        require(msg.sender == marketplaceAddress, "Only the marketplace can call this function");
        _;
    }

    // functions
    function setMarketplaceAddress(address _marketplaceAddress) public onlyOwner {
        require(marketplaceAddress == address(0), "Marketplace address already set");
        marketplaceAddress = _marketplaceAddress;
    }

    function getOwner(uint256 _id) external view returns (address) {
        require(_id < nextId, "Microgrid does not exist");
        return microgrids[_id].owner;
    }

    function isMicrogridActive(uint256 _id) external view returns (bool) {
        require(_id < nextId, "Microgrid does not exist");
        return microgrids[_id].isActive;
    }

    function registerMicrogrid(string memory _name, uint256 _latitude, uint256 _longitude, uint256 _maxCapacity) public {
        require(_maxCapacity > 0, "Max capacity must be greater than zero");
        require(!isRegistered[msg.sender], "Microgrid already registered for this owner");
        uint256 id = nextId++;
        microgrids[id] = Microgrid({
            id: id,
            name: _name,
            owner: msg.sender,
            latitude: _latitude,
            longitude: _longitude,
            energyGenerated: 0,
            energyDemand: 0,
            batteryLevel: 100,
            maxCapacity: _maxCapacity,
            reservedEnergy: 0,
            isActive: true,
            lastUpdated: block.timestamp
        });

        isRegistered[msg.sender] = true;
        emit MicrogridRegistered(id, msg.sender, _name, _latitude, _longitude);
    }

    function updateStatus(uint256 _id, uint256 _energyGenerated, uint256 _energyDemand, uint256 _batteryLevel) public onlyMicrogridOwner(_id) {
        require(_id < nextId, "Microgrid does not exist");
        require(microgrids[_id].isActive, "Microgrid is not active");
        require(_batteryLevel <= 100, "Battery level must be between 0 and 100");
        require(_energyGenerated <= microgrids[_id].maxCapacity, "Energy generated exceeds max capacity");
        require(_energyDemand <= microgrids[_id].maxCapacity, "Energy demand exceeds max capacity");

        microgrids[_id].energyGenerated = _energyGenerated;
        microgrids[_id].energyDemand = _energyDemand;
        microgrids[_id].batteryLevel = _batteryLevel;

        microgrids[_id].lastUpdated = block.timestamp;

        emit StatusUpdated(_id, _energyGenerated, _energyDemand, _batteryLevel, block.timestamp);
    }

    function getSurplus(uint256 _id) public view returns(int256){
        require(_id < nextId, "Microgrid does not exist");
        require(microgrids[_id].isActive, "Microgrid is not active");
        return int256(microgrids[_id].energyGenerated) - int256(microgrids[_id].energyDemand) - int256(microgrids[_id].reservedEnergy);
    }

    function hasSurplus(uint256 _id) public view returns(bool){
        require(_id < nextId, "Microgrid does not exist");
        require(microgrids[_id].isActive, "Microgrid is not active");
        return int256(microgrids[_id].energyGenerated) - int256(microgrids[_id].energyDemand) - int256(microgrids[_id].reservedEnergy) > 0;
    }

    function getAvailableEnergy(uint256 _id) external view returns(uint256){
        require(_id < nextId, "Microgrid does not exist");
        require(microgrids[_id].isActive, "Microgrid is not active");
        int256 availableEnergy = int256(microgrids[_id].energyGenerated) - int256(microgrids[_id].energyDemand) - int256(microgrids[_id].reservedEnergy);
        return availableEnergy > 0 ? uint256(availableEnergy) : 0;
    }

    function getMicrogrid(uint256 _id) public view returns (Microgrid memory) {
        require(_id < nextId, "Microgrid does not exist");
        return microgrids[_id];
    }

    function setMicrogridStatus(uint256 _id, bool _status) public onlyMicrogridOwner(_id) {
        require(_id < nextId, "Microgrid does not exist");
        microgrids[_id].isActive = _status;
    }

    function increaseReservedEnergy(uint256 _id, uint256 _amount) external onlyMarketplace {
        require(_id < nextId, "Microgrid does not exist");
        microgrids[_id].reservedEnergy += _amount;

        emit ReservedEnergyUpdated(_id, microgrids[_id].reservedEnergy);
    }

    function decreaseReservedEnergy(uint256 _id, uint256 _amount) external onlyMarketplace {
        require(_id < nextId, "Microgrid does not exist");
        require(microgrids[_id].reservedEnergy >= _amount, "Insufficient reserved energy");
        microgrids[_id].reservedEnergy -= _amount;

        emit ReservedEnergyUpdated(_id, microgrids[_id].reservedEnergy);
    }
    
    function getPricingData(uint256 _id) external view returns(uint256 generation, uint256 demand, uint256 batteryLevel, uint256 maxCapacity, uint256 reservedEnergy){
        require(_id < nextId, "Microgrid doesn't exist");

        Microgrid storage grid = microgrids[_id];

        return(
            grid.energyGenerated, 
            grid.energyDemand, 
            grid.batteryLevel, 
            grid.maxCapacity, 
            grid.reservedEnergy
        );
    }
}

contracts/PricingLibrary.sol.content:
// SPDX-License-Identifier: UNLICENSED

pragma solidity ^0.8.0;

// Price = Base Price + Demand Factor - Generation Factor + Battery Factor + Peak Hour Factor


// Availability Score = (generation + batteryReserve) / (demand + reservedEnergy)

library PricingLibrary{
    uint256 constant BASE_PRICE = 10; // 10 ETK/kWh

    uint256 constant HIGH_SURPLUS_DISC = 2;
    uint256 constant MID_SURPLUS_DISC = 1;

    uint256 constant LOW_SURPLUS_PREMIUM = 2;
    uint256 constant DEFICIT_SURPLUS_PREMIUM = 4;

    uint256 constant HIGH_BATTERY_DISC = 2;
    uint256 constant MID_BATTERY_DISC = 1;

    uint256 constant LOW_BATTERY_PREMIUM = 2;
    uint256 constant DEFICIT_BATTERY_PREMIUM = 4;

    function calculatePrice(
        uint256 generation, 
        uint256 demand, 
        uint256 batteryLevel, 
        uint256 maxCapacity, 
        uint256 reservedEnergy
    ) external pure returns (uint256){
        uint256 price = BASE_PRICE;

        int256 availableEnergy = int256(generation) - int256(demand) - int256(reservedEnergy);
        int256 availabilityRatio = (availableEnergy * 100) / int256(maxCapacity);

        // availibilty adjustments
        if(availabilityRatio >= 70) price -= HIGH_SURPLUS_DISC;
        else if(availabilityRatio >= 40) price -= MID_SURPLUS_DISC;
        else if(availabilityRatio >= 20) price += 0;
        else if(availabilityRatio >= 0) price += LOW_SURPLUS_PREMIUM;
        else price += DEFICIT_SURPLUS_PREMIUM;

        // battery level adjustments
        if(batteryLevel >= 80) price -= HIGH_BATTERY_DISC;
        else if(batteryLevel >= 60) price -= MID_BATTERY_DISC;
        else if(batteryLevel >= 40) price += 0;
        else if(batteryLevel >= 20) price += LOW_BATTERY_PREMIUM;
        else price += DEFICIT_BATTERY_PREMIUM;

        if(price < 1) price = 1;

        return price;
    }

    function calculateCost(uint256 _price, uint256 _amt) external pure returns (uint256) {
        require(_amt > 0, "Amount must be greater than 0");
        return (_amt * _price);
    }
}

